def cache_get(key):
    try:
        value = memcache_client.get(key)
        if value is None:
            return None
        if isinstance(value, bytes):
            value = value.decode("utf-8")
        return json.loads(value)
    except Exception:
        return None


def cache_set(key, value, ttl):
    try:
        memcache_client.set(key, json.dumps(value), expire=ttl)
    except Exception:
        pass


def cache_delete(key):
    try:
        memcache_client.delete(key)
    except Exception:
        pass


def make_cache_key(prefix, payload):
    raw = json.dumps(payload, sort_keys=True, separators=(",", ":"))
    digest = hashlib.sha256(raw.encode("utf-8")).hexdigest()
    return f"{prefix}:{digest}"


def api_cache(ttl=API_RESPONSE_CACHE_TTL):
    def decorator(fn):
        @wraps(fn)
        def wrapper(*args, **kwargs):
            payload = {
                "path": request.path,
                "args": request.args.to_dict(flat=False),
                "method": request.method,
            }
            key = make_cache_key("api", payload)
            cached = cache_get(key)
            if cached is not None:
                return jsonify({"cached": True, "data": cached}), 200

            response = fn(*args, **kwargs)
            if isinstance(response, tuple):
                body, status = response
            else:
                body, status = response, 200

            if status == 200:
                if hasattr(body, "get_json"):
                    data = body.get_json()
                else:
                    data = body
                cache_set(key, data, ttl)
                return jsonify({"cached": False, "data": data}), 200

            return response

        return wrapper

    return decorator


def query_items(category=None, min_price=None, max_price=None):
    query_payload = {
        "category": category,
        "min_price": min_price,
        "max_price": max_price,
    }
    cache_key = make_cache_key("db:items", query_payload)
    cached = cache_get(cache_key)
    if cached is not None:
        return cached, True

    sql = "SELECT id, name, category, price, updated_at FROM items WHERE 1=1"
    params = []

    if category:
        sql += " AND category = ?"
        params.append(category)
    if min_price is not None:
        sql += " AND price >= ?"
        params.append(min_price)
    if max_price is not None:
        sql += " AND price <= ?"
        params.append(max_price)

    sql += " ORDER BY id"

    conn = get_db()
    cur = conn.cursor()
    cur.execute(sql, params)
    rows = cur.fetchall()
    conn.close()

    result = [dict(row) for row in rows]
    cache_set(cache_key, result, DB_QUERY_CACHE_TTL)
    return result, False


