@app.route("/items", methods=["POST"])
def create_item():
    data = request.get_json(silent=True) or {}
    name = data.get("name")
    category = data.get("category")
    price = data.get("price")

    if not name or not category or price is None:
        return jsonify({"error": "name, category, and price are required"}), 400

    now = int(time.time())
    conn = get_db()
    cur = conn.cursor()
    cur.execute(
        "INSERT INTO items (name, category, price, updated_at) VALUES (?, ?, ?, ?)",
        (name, category, float(price), now),
    )
    item_id = cur.lastrowid
    conn.commit()
    conn.close()

    cache_delete(f"db:item:{item_id}")

    return jsonify(
        {
            "message": "Item created",
            "item": {
                "id": item_id,
                "name": name,
                "category": category,
                "price": float(price),
                "updated_at": now,
            },
            "note": "List/API caches will expire automatically based on TTL",
        }
    ), 201


